/**
 * Returns the sine in radians from a lookup table. For optimal precision, use radians between -PI2 and PI2 (both
 * inclusive).
 */
static public float sin(float radians) {
    return Sin.table[(int) (radians * radToIndex) & SIN_MASK];
}
